import {  STATUS } from '../../utils/constants';
import {notifyResponseMessage} from '../commoncomponent/NotificationComponent/notifyResponseMessage';
import {BASE_PATH_APIS} from '../../utils/constants';
import axios from 'axios';

class DataValidationService {

    async fetchValidationFields( type){
        console.log("Base path fetchValidationFields: "+BASE_PATH_APIS.basePathForAPIS);
        try{
            const response = await axios.get(BASE_PATH_APIS.basePathForAPIS+'/app/rest/label_generation/get_validation_fields',
            {
                params: {                    
                    type:type,                            
                }
            });
            
            return response;         
        } catch (error) {

            notifyResponseMessage(STATUS.ERROR, error);
        }
        return null;
    }

    async saveValidationFields(validations,attributeId,attributeValidationId){
        try{
            const response = await axios.post(BASE_PATH_APIS.basePathForAPIS+'/app/rest/label_generation/addOrUpdate/fieldValidation',{
                validations: validations,
                attributeId:attributeId,
                attributeValidationId:attributeValidationId
            });
            
            return response;         
        } catch (error) {

            notifyResponseMessage(STATUS.ERROR, error);
        }
        return null;
    }

    async saveValidationRule(dataValidationRequestDto){
        try{
            const response = await axios.post(BASE_PATH_APIS.basePathForAPIS+'/app/rest/label_generation/addOrUpdate_rules',dataValidationRequestDto);
            
            return response;         
        } catch (error) {

            notifyResponseMessage(STATUS.ERROR, error);
        }
        return null;
    }

    async fetchRegexGuide(){
        console.log("Base path fetchRegexGuide: "+BASE_PATH_APIS.basePathForAPIS);
        try{
            const response = await axios.get(BASE_PATH_APIS.basePathForAPIS+'/app/rest/label_generation/get_regex_guide');
            return response;         
        } catch (error) {

            notifyResponseMessage(STATUS.ERROR, error);
        }
        return null;
    }

    async fetchValidationRule(){
        console.log("Base path fetchValidationRule: "+BASE_PATH_APIS.basePathForAPIS);
        try{
            const response = await axios.get(BASE_PATH_APIS.basePathForAPIS+'/app/rest/label_generation/get_validation_rules');
            return response;         
        } catch (error) {

            notifyResponseMessage(STATUS.ERROR, error);
        }
        return null;
    }  

    async deleteValidationRule(ruleId){
        try{
            const response = await axios.post(BASE_PATH_APIS.basePathForAPIS+'/app/rest/label_generation/delete/validation_rules?ruleId='+ruleId);
            return response;         
        } catch (error) {

            notifyResponseMessage(STATUS.ERROR, error);
        }
        return null;
    }
    
}
export const dataValidationService = new DataValidationService();
